import {
  Children,
  cloneElement,
  Fragment,
  isValidElement,
  type JSX,
  type PropsWithChildren,
  type ReactNode,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { useIntl } from 'react-intl';

import { ChevronDownSmallIcon, CrosshairIcon } from '@dynatrace/strato-icons';

import { Button } from '../../../../../buttons/button/Button.js';
import { Menu } from '../../../../../navigation/menu/Menu.js';
import { Tooltip } from '../../../../../overlays/tooltip/Tooltip.js';
import { useA11yToolbarTabIndex } from '../../../hooks/useA11yToolbarTabIndex.js';
import { useToolbarContext } from '../hooks/useToolbarContext.js';
import { TOOLBAR_MESSAGES } from '../messages.js';
import {
  styledToolbarMenuContainer,
  toolbarMenuGroup,
} from './ToolbarMenu.sty.js';

interface ChartToolbarMenuProps {
  children: ReactNode;
  onMenuOpen: (open: boolean) => void;
  isOpen?: boolean;
  onMenuEnter?: () => void;
  onMenuLeave?: () => void;
  activeModeIcon?: JSX.Element;
  triggerLabel?: string;
  menuAlignment?: 'start' | 'end';
  onCloseAutoFocus?: (event: Event) => void;
  isDownloadEnabled?: boolean;
  toolbarDisplayMode?: 'overlay' | 'inline';
  /** Behaviour tracking attribute */
  'data-dt-name'?: string;
  /** Behaviour tracking attribute */
  'data-dt-properties'?: string;
}

function renderMenuItems(children: ReactNode): ReactNode {
  return Children.map(children, (child) => {
    if (isValidElement<PropsWithChildren>(child)) {
      if (child.type === Fragment) {
        return renderMenuItems(child.props.children);
      }

      return cloneElement(child, {
        ...child.props,
      });
    }

    return child;
  });
}

/**
 * ChartToolbarMenu component for displaying a dropdown menu
 */
export const ToolbarMenu = (props: ChartToolbarMenuProps) => {
  const {
    children,
    onMenuOpen,
    isOpen,
    activeModeIcon,
    triggerLabel,
    onMenuEnter,
    onMenuLeave,
    menuAlignment = 'start',
    onCloseAutoFocus,
    'data-dt-name': dtName,
    'data-dt-properties': dtProperties,
  } = props;
  const [isHoverChartToolsIcon, setIsHoverChartToolsIcon] =
    useState<boolean>(false);
  const menuTriggerButtonRef = useRef<HTMLButtonElement>(null);
  const tabIndex = useA11yToolbarTabIndex('explore');
  const intl = useIntl();
  const { isExpanded } = useToolbarContext();

  const menuItems = useMemo(() => renderMenuItems(children), [children]);

  useEffect(() => {
    if (tabIndex === 0 && menuTriggerButtonRef.current) {
      menuTriggerButtonRef.current?.focus();
    }
  }, [menuTriggerButtonRef, tabIndex]);

  const chartActionsButton = useMemo(() => {
    const tooltipText = isExpanded
      ? triggerLabel ?? intl.formatMessage(TOOLBAR_MESSAGES.changeMode)
      : intl.formatMessage(TOOLBAR_MESSAGES.chartTools);

    const handleMenuOpenChange = (isOpen: boolean) =>
      setIsHoverChartToolsIcon(isOpen);

    return (
      <Tooltip
        text={tooltipText}
        open={isHoverChartToolsIcon}
        onOpenChange={handleMenuOpenChange}
      >
        <Menu.Trigger>
          <Button
            variant="default"
            size="condensed"
            ref={menuTriggerButtonRef}
            tabIndex={tabIndex}
            data-dt-name={dtName}
            data-dt-properties={dtProperties}
          >
            <Button.Prefix>{activeModeIcon ?? <CrosshairIcon />}</Button.Prefix>
            <Button.Suffix>
              <ChevronDownSmallIcon />
            </Button.Suffix>
          </Button>
        </Menu.Trigger>
      </Tooltip>
    );
  }, [
    isHoverChartToolsIcon,
    isExpanded,
    activeModeIcon,
    triggerLabel,
    intl,
    tabIndex,
    dtName,
    dtProperties,
  ]);

  const handleOnMouseEnter = () => {
    onMenuEnter?.();
  };

  const handleOnMouseLeave = () => {
    onMenuLeave?.();
  };

  return (
    <div
      className={styledToolbarMenuContainer({
        inline: props.toolbarDisplayMode === 'inline',
      })}
      onMouseEnter={handleOnMouseEnter}
      onMouseLeave={handleOnMouseLeave}
    >
      <Menu onOpenChange={onMenuOpen} open={isOpen}>
        {chartActionsButton}
        <Menu.Content
          alignment={menuAlignment}
          onCloseAutoFocus={onCloseAutoFocus}
        >
          <Menu.Group className={toolbarMenuGroup}>{menuItems}</Menu.Group>
        </Menu.Content>
      </Menu>
    </div>
  );
};
